using System; using System.Web.Http; using PoslovnaLogika; using KlasePodataka; namespace RegistracijaVozilaServis.Controllers { public class ZahtevController:ApiController { [HttpPost] public IHttpActionResult ProveriUslove([FromBody] ZahtevZaRegistracijuKlasa z){try{var l=new ZahtevPoslovnaLogika();z.IspunjavaOsnovneUslove=l.ProveriDaLiKandidatIspunjavaUslove(z.RokKonkursa,true);z.StatusZahteva=z.IspunjavaOsnovneUslove?"Primljena":"Odbijena";return Ok(z);}catch(Exception e){return BadRequest(e.Message);}} }}